var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 이게 무슨 소리지?","JPN":"うん？　これは何の音？","ENG":"Mm... What's that noise?","TWN":"呃嗯，這是什麼聲音？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴, 아카데미? 아니야, 뭔가 다른데?","JPN":"ここはアカデミー？　いや、何かが違うような？","ENG":"Is this... the Academy? No, something's different.","TWN":"這裡是，學院？不對，不太一樣。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 학생 여러분.","JPN":"生徒の皆様、お待たせいたしました。","ENG":"Dear students, thank you for your patience.","TWN":"同學們，大家久等了。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조화와 화합의 학원제, 애쉬포드 학원제가 내일로 다가왔습니다. 모두 후회없는 축제 준비를 부탁드리겠습니다.","JPN":"いよいよ調和と和合の学園祭、アッシュフォード学園祭が明日へと迫りました。\\n皆さん、悔いのないように準備をお願いします。","ENG":"Tomorrow is the Harmony and Balance Festival at Ashford Academy. I hope everyone makes every effort to prepare for the festival.","TWN":"明天就是全校同歡的阿什弗德學園祭，請大家做足準備，不要留下遺憾。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학원제라고? 분명 페스타는 중지…….","JPN":"学園祭！？　確か学園祭は中止するって……","ENG":"Festival? But I clearly remember her saying that it was canceled...","TWN":"學園祭？不是說暫停……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 내가 방금 무슨 말을 하려고 했더라?","JPN":"あれ？　私今何を言おうとしたんだっけ？","ENG":"Huh? What was I about to say just now?","TWN":"嗯？我剛要說什麼？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼, 나이엘 양. 학원제 예행연습을 해볼까요? 시작 구호는 올해 학년대표인 당신의 역할이었죠?","JPN":"では、ナイエルさん。明日の予行演習をしましょう。\\n学園祭開始の掛け声は今年の学年代表であるあなたの役でしたよね？","ENG":"Then, Naielle. Shall we do a rehearsal of the festival? As this year's student representative, you were in charge of shouting the slogan, correct?","TWN":"奈爾，那我們就來彩排吧？你是今年負責\\n喊開始口號的學生代表，你知道要做什麼吧？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"회장. 근데 이거 꼭 해야 돼?","JPN":"会長。これって必ずやらなきゃいけないの？","ENG":"Yen, do I really have to do this?","TWN":"會長，一定要這樣嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"물론이에요. 나이엘 양. 이건 애쉬포드의 전통이니까요.","JPN":"もちろんです、ナイエルさん。これはアッシュフォードの伝統ですから。","ENG":"Of course, Naielle. It's Ashford tradition.","TWN":"當然要。奈爾，這是阿什弗德的傳統。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으…… 그, 그럼……","JPN":"むう……、じ、じゃあ……","ENG":"Ugh... Th-then...","TWN":"喔……那，那好吧……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"냐, 냐……","JPN":"にゃ、にゃ……","ENG":"Me, meo–","TWN":"喵，喵……"},"stage":{"bg":"SKY","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 못하겠어! 못하겠다구!! 전교생이 듣는데 부끄럽게 그걸 어떻게 해!?","JPN":"うう、やっぱりできない！　できないわよ！\\n全校生徒の前でこんな恥ずかしいことできるわけないでしょ！","ENG":"Bah! I can't do it! I just can't!! How can I say that in front of everybody without getting embarrassed?!","TWN":"唉唷，我不行啦！我做不到！！全校學生都會聽到欸，那麼害羞，我沒辦法啦！"},"stage":{"bg":"SKY","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"흐음, 역시 그런가요? 곤란하네요.","JPN":"ふむ、やはりそうですか。困りましたね。","ENG":"Hmm, is that so? That's a shame.","TWN":"嗯嗯，是嗎？真傷腦筋。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 양이 못하시겠다면, 시작 구호는 다른 학년 대표에게……","JPN":"ナイエルさんができないなら、他の学年の代表に……","ENG":"If you can't do it, Naielle, then we will need to give the honors to another repre–","TWN":"既然奈爾不行，那我只好找其他人來……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건 안 돼!!","JPN":"そ、それはダメ！","ENG":"N-no!!","TWN":"不，不可以！！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 내일은 진짜 제대로 할 수 있어! 믿어달라구, 회장!","JPN":"うう、明日はちゃんとできるから！　信じてよ、会長！","ENG":"Errgh, I'll do it properly tomorrow! I promise!","TWN":"那個，我明天一定會好好表現的！你相信我，會長！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 지금 건? 전야제 준비 방송인가?","JPN":"なんだ、今の？　前夜祭の準備放送か？","ENG":"Huh? What was that? Was that the rehearsal broadcast for tomorrow's festival?","TWN":"剛那是怎樣？是在彩排嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 평소대로의 학생회 같은 분위기잖아? 내일 학원제가 기대되는 걸?","JPN":"ふふっ。でも、生徒会らしいじゃない。明日の学園祭が楽しみね。","ENG":"Well, it's just any other day for the Student Council. Anyway, I'm hyped about tomorrow's festival!","TWN":"不是學生會的日常發揮嗎？真期待明天的學園祭。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 대체 뭐가 어떻게 돌아가는 거야?","JPN":"ちょっと待って、いったい何がどうなっているの？","ENG":"Wait a minute. What's going on around here?","TWN":"等等，現在到底是什麼情況？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"미나야!","JPN":"ミナ！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"정말! 이런 곳에서 뭘 하고 있어! 다들 널 얼마나 찾았는데!","JPN":"もう！　こんなところで何してるの？　みんな探してたんだよ！","ENG":"Seriously? What are you doing here? Everyone's been looking all over for you!","TWN":"真是的！你在這裡做什麼！大家都在找你！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"자, 빨리 학생회실로 가자.","JPN":"さあ、はやく生徒会室に行こう。","ENG":"C'mon. Let's hurry and head to the Student Council office.","TWN":"走吧，我們快回去學生會辦公室吧。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나를 찾았다고? 그것보다 누구야, 넌? 나를 알아?","JPN":"私を探していたの？　それより、あなたは誰？　私を知っているの？","ENG":"They're looking for me? But, who are you? Do you know me?","TWN":"找我？你是誰？你認識我嗎？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"무슨 소리하는 거야, 유미나! 전학 온 지 얼마 안 되긴 했지만, 너도 학생회 임원이잖아?","JPN":"何を言っているの、あなたはヤナギ・ミナでしょう？\\n転校してきたばかりだけど、あなたも生徒会役員じゃない。","ENG":"What are you talking about, Yoo Mina! I know you just transferred here, but you're a member of the Student Council, remember?","TWN":"你在發什麼神經，劉米娜！雖然你才剛轉學過來沒多久，但你也是學生會的幹部好嗎！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 학생회 임원이라고?","JPN":"私が生徒会役員？","ENG":"I'm a Student Council member?","TWN":"我是學生會的幹部？"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_QM","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그랬……었지. 미안, 셜리. 잠깐 잊고 있었나 봐.","JPN":"そう……だったよね。ごめんね、シャーリー。\\nうっかりしていたみたい。","ENG":"That's... right. Sorry. I guess I forgot.","TWN":"好像……是吼？抱歉，夏麗，我突然想不起來。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"정말, 미나는 의외로 멍한 구석이 있다니까.","JPN":"もう、ミナったら。意外と抜けているところがあるんだよね。","ENG":"Ugh, you can be really inattentive sometimes, Mina.","TWN":"真是的，沒想到米娜也有粗線條的一面。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래……. 나도 학생회 임원이면 학원제 준비를…….","JPN":"そうだ……私は生徒会役員だから、学園祭の準備を進めなきゃ……","ENG":"Right... As a Student Council member, I should also help with the festival preparations...","TWN":"沒錯……我也是學生會的幹部，要準備學園祭……"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"자, 빨리 서둘러! 모두 널 기다리고 있어.","JPN":"そうだよ。さあ、急いで！　みんな待ってるから。","ENG":"C'mon, hurry up! Everyone's waiting for you.","TWN":"快點走吧！大家都在等你呢。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"얘들아! 미나를 데려왔어","JPN":"みんな！　ミナを連れてきたよ。","ENG":"Guys! I brought Mina!","TWN":"大家！我把米娜帶來囉。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오셨군요. 막 회의를 시작하려던 참이었습니다.","JPN":"来ましたか。ちょうど会議を始めようとしたところです。","ENG":"You're here. We were just about to start our meeting.","TWN":"你來啦，會議才正要開始而已。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_QM","text":{"KOREA":"늦었군, 미나.","JPN":"遅かったな、ミナ。","ENG":"You're late, Mina.","TWN":"米娜，你遲到了。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_QM","text":{"KOREA":"안녕, 미나.","JPN":"こんにちは、ミナ。","ENG":"Hey, Mina.","TWN":"嗨，米娜。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_QM","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너희들은……?","JPN":"あなたたちは……？","ENG":"Who're you guys...?","TWN":"你們是……？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아! 부회장인 를르슈! 그리고 옆에는 카렌이었지?","JPN":"あっ。副会長のルルーシュ。それに隣はカレンだよね？","ENG":"Oh! Vice President Lelouch! And next to him is Kallen, was it?","TWN":"對了！你是副會長魯路修！在你旁邊的是卡蓮對吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그래. 그 말대로 난 부회장인 를르슈 람페르지. 그리고 이쪽은 코우즈키 카렌이야.","JPN":"ああ。知ってのとおり、俺は副会長のルルーシュ・ランペルージ。\\nそれに、こっちは紅月カレンだ。","ENG":"Correct. I am Lelouch Lamperouge, the Vice President. And this here is Kallen Kozuki.","TWN":"你說的沒錯，我是副會長，魯路修·蘭佩洛基，而這位是紅月卡蓮。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"정말이지, 미나는 의외로 멍한 구석이 있구나.","JPN":"もう、ミナったらボンヤリしてるんだから。","ENG":"Mina, you like to zone out, don't you?","TWN":"真沒想到米娜也有糊塗的一面。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으응…… 미안.","JPN":"う、うん……ごめんなさい。","ENG":"Y-yeah... Sorry.","TWN":"嗯嗯……抱歉。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 전학생 주제에 어디서 빈둥거리다가 이제 나타나는 거야?","JPN":"ちょっとあんた！　転校生のくせにどこでチンタラしてたの？","ENG":"What? How dare a transfer student be so late?!","TWN":"搞什麼？你這個轉學生是跑去哪裡摸魚，現在才出現？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_QM","text":{"KOREA":"나이엘 양. 그렇게 심하게 말할 필요는 없잖아요.","JPN":"ナイエルさん、そこまでキツく言わなくても……","ENG":"Naielle, you don't have to be so harsh on her like that.","TWN":"奈爾，不需要這麼兇吧。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_QM","text":{"KOREA":"미나 양한테도 사정이 있었을 지도 모르는데…….","JPN":"ミナさんにも事情があるかもしれませんし……","ENG":"I'm sure Mina had her reasons for being late...","TWN":"米娜可能是因為有什麼事才……"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어? 사정? 무슨 사정!?","JPN":"はあ？　事情？　何の事情よ！？","ENG":"Whaaaat? Reasons? What kind of reasons, huh?!","TWN":"什麼？有事？能有什麼事！？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"무릇 학생이라면 학원제에 목숨을 바치는 게 상식이라구! 학년 대표로서 자각을 가지는 게 어때, 타피르 선배?","JPN":"この学園の生徒なら学園祭に命をかけるのが常識なのよ！\\n同じ学年代表として少しは自覚を持ったらどうなの、タピル先輩？","ENG":"It's common sense for students to devote their lives to the school festival! You should be more aware of that as a student representative, Tapir.","TWN":"身為學生，為學園祭獻上生命不是基本常識嗎！身為學生代表，我勸你要有點自覺，達爾前輩？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"야, 나이엘! 선배한테 말 버릇이 그게 뭐야?","JPN":"ちょっと、ナイエル！\\n先輩に向ってそんな言い方しちゃダメじゃない。","ENG":"Hey, Naielle! That's no way to talk to your seniors!","TWN":"奈爾！你怎麼可以這樣對前輩說話？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 시끄러워, 참견쟁이! 이 멀대가 자꾸 답답하게 구는 걸 어떡해?","JPN":"ふん！　うるさい、お節介焼き！\\nこのヒョロヒョロがぬるすぎるのがいけないのよ！","ENG":"Hmph! Shut it, nosy! It's not my fault this giraffe is acting so irritably!","TWN":"哼！要你管，雞婆！這傻大個老是惹我生氣，能怎麼辦？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 저기 갑자기 끼어들어서 미안한데…….","JPN":"えっと、話に割り込んで申し訳ないけど……","ENG":"Um, sorry for interrupting you, but...","TWN":"呃，那個，不好意思打個岔……"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단, 우리 다 같은 학교가 맞긴 한 거지?","JPN":"とりあえず、私たちは全員同じ学校の生徒なんだよね？","ENG":"We all go to the same school, right?","TWN":"我想問，我們都是同一所學校的對吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"넌 또 무슨 헛소리를 하는 거야, 그거야 당연하지!","JPN":"あんたはまた何を言ってるの？　当たり前でしょ？","ENG":"What kind of a crazy talk is that? Of course!","TWN":"你又在胡說八道什麼，那還用說嗎！"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래? 그럼 왜 다 교복이 제각각인 거야?","JPN":"だよね？　でもなんでみんな制服がバラバラなの？","ENG":"Really? But then, why are all our uniforms different?","TWN":"是嗎？那為什麼大家的制服都不一樣？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"미나, 혹시 어디 아파? 왠지 아까부터 상태가 안 좋아 보이긴 했는데…….","JPN":"ミナ、どこか具合でも悪いの？　さっきからソワソワしてるし……","ENG":"Mina, are you feeling ill? You don't seem very well...","TWN":"米娜，你是不是哪裡不舒服？你從剛才就狀態不太好的樣子……"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 내가 지금 못할 말이라도 한 거야?","JPN":"な、なに？\\nこの言っちゃいけないことを言ったみたいな雰囲気は？","ENG":"H-huh? Did I say something I shouldn't?","TWN":"怎，怎麼了嗎？我說錯話了嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"너어! 몰라서 물어? 우리 학교에서 복장 지적은 금기라고!","JPN":"あんた！　それ本気で聞いてんの？　うちの学園で服装の指摘は禁忌なの！","ENG":"Hey! You seriously don't know? Talking about clothes in school is forbidden, remember?!","TWN":"你！是真不知道，還假不知道？在我們學校是禁止對制服說三道四的！"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어째서 그런 상식을 모르는 거야!?","JPN":"なんでそんな常識もわからないの！？","ENG":"It's common sense! C'mon!","TWN":"你連這點常識都沒有嗎！？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_QM","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"상식이라고? 그게?","JPN":"常識？　それが？","ENG":"That's common sense?","TWN":"這是常識嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양. 우리 학교는 복식의 자유를 존중하기 위해 교복 착용을 강제하지 않습니다.","JPN":"ミナさん、私たちのアカデミーは\\n服装の自由を尊重するために、制服を強制しません。","ENG":"Mina, our school does not require students to wear the school uniform out of respect for their right to dress however they want.","TWN":"本學院尊重學生的穿著自由，不會強制要求學生穿校服。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저 또한 학생들의 다양한 개성을 수렴해야 하는 학생회장으로서, 타의 귀감이 되기 위해 이렇게 입기 시작했고요.","JPN":"私も生徒の多様性を受け入れるべき生徒会長として、\\n皆さんの模範となるためこのような服装をしています。","ENG":"So, as their representative, I started wearing clothes like these to show them that they can wear whatever they want to express their uniqueness.","TWN":"而作為必需包容學生不同個性的學生會長，就得以身作則才行，所以我才開始這樣穿的。"},"stage":{"bg":"GEASS_ROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쩐지 그거 익숙한 논리인데…… 기분 탓인가?","JPN":"何となく聞き慣れた理論のような……気のせいかな？","ENG":"That reasoning sounds familiar... Is it just me?","TWN":"怎麼覺得好像聽過這段話……是心理作用嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그보다 회장, 미나도 도착했으니 슬슬 회의를 시작하는 게 어떨까요?","JPN":"それより会長、ミナも着いたのでそろそろ会議を始めましょう。","ENG":"Yen, Mina's here, so shall we start the meeting?","TWN":"會長，米娜也到了，那就開始會議吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 그럼 지금부터 학생회 임원 회의를 시작할까요?","JPN":"そうですね。それでは、これより生徒会役員会議を始めます。","ENG":"I see. Then, shall we begin our Student Council meeting now?","TWN":"也是，那現在就開始進行學生會幹部會議吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};